import { AutoProcessor, CLIPVisionModelWithProjection, RawImage, env } from '@xenova/transformers';

// Configure transformers.js for CRA compatibility
env.allowLocalModels = false;
env.allowRemoteModels = true;
env.useBrowserCache = false;
env.useFSCache = false;
if (env.backends?.onnx?.wasm) {
  env.backends.onnx.wasm.wasmPaths = '/admin/';
}

// ── Singleton CLIP vision model + processor ──────────────────────────────────
let modelPromise = null;

function initCLIP() {
  if (!modelPromise) {
    console.log('[CLIP] Loading vision model + processor...');
    modelPromise = Promise.all([
      CLIPVisionModelWithProjection.from_pretrained('Xenova/clip-vit-base-patch32'),
      AutoProcessor.from_pretrained('Xenova/clip-vit-base-patch32'),
    ]).then(([model, processor]) => {
      console.log('[CLIP] Model ready');
      return { model, processor };
    }).catch(err => {
      console.error('[CLIP] Model load failed:', err);
      modelPromise = null;
      throw err;
    });
  }
  return modelPromise;
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function normalize(vec) {
  const norm = Math.sqrt(vec.reduce((sum, v) => sum + v * v, 0));
  if (norm === 0) return vec;
  return vec.map(v => v / norm);
}

/**
 * Load an image URL into an HTMLImageElement.
 * Uses fetch + blob URL to avoid CORS issues with Firebase Storage URLs.
 * Falls back to direct loading for data URLs and same-origin URLs.
 */
async function loadImage(url) {
  return new Promise(async (resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`Failed to load: ${url.substring(0, 80)}`));

    if (url.startsWith('data:') || url.startsWith('blob:')) {
      img.src = url;
    } else {
      // Fetch as blob to bypass CORS restrictions on Firebase Storage URLs
      try {
        const res = await fetch(url);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const blob = await res.blob();
        img.src = URL.createObjectURL(blob);
      } catch (err) {
        reject(new Error(`Fetch failed for ${url.substring(0, 80)}: ${err.message}`));
      }
    }
  });
}

// ── Augmentation ─────────────────────────────────────────────────────────────

const CANVAS_SIZE = 224;

/**
 * Draw the source image onto a canvas with the given transform, return a data URL.
 */
function drawVariant(img, transformFn) {
  const canvas = document.createElement('canvas');
  canvas.width = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;
  const ctx = canvas.getContext('2d');
  transformFn(ctx, img, CANVAS_SIZE);
  return canvas.toDataURL('image/jpeg', 0.85);
}

/**
 * Generate augmented variants of an image.
 * Returns an array of data URL strings (original + augmentations).
 */
function generateAugmentations(img) {
  const variants = [];

  // 1. Original
  variants.push(drawVariant(img, (ctx, img, size) => {
    ctx.drawImage(img, 0, 0, size, size);
  }));

  // 2. Rotated +5°
  variants.push(drawVariant(img, (ctx, img, size) => {
    ctx.translate(size / 2, size / 2);
    ctx.rotate((5 * Math.PI) / 180);
    ctx.translate(-size / 2, -size / 2);
    ctx.drawImage(img, 0, 0, size, size);
  }));

  // 3. Rotated -5°
  variants.push(drawVariant(img, (ctx, img, size) => {
    ctx.translate(size / 2, size / 2);
    ctx.rotate((-5 * Math.PI) / 180);
    ctx.translate(-size / 2, -size / 2);
    ctx.drawImage(img, 0, 0, size, size);
  }));

  // 4. Rotated +10°
  variants.push(drawVariant(img, (ctx, img, size) => {
    ctx.translate(size / 2, size / 2);
    ctx.rotate((10 * Math.PI) / 180);
    ctx.translate(-size / 2, -size / 2);
    ctx.drawImage(img, 0, 0, size, size);
  }));

  // 5. Brightness +20%
  variants.push(drawVariant(img, (ctx, img, size) => {
    ctx.drawImage(img, 0, 0, size, size);
    ctx.globalCompositeOperation = 'lighter';
    ctx.fillStyle = 'rgba(255,255,255,0.2)';
    ctx.fillRect(0, 0, size, size);
  }));

  // 6. Brightness -20%
  variants.push(drawVariant(img, (ctx, img, size) => {
    ctx.drawImage(img, 0, 0, size, size);
    ctx.globalCompositeOperation = 'multiply';
    ctx.fillStyle = 'rgba(200,200,200,1)';
    ctx.fillRect(0, 0, size, size);
  }));

  // 7. Center crop (80%)
  variants.push(drawVariant(img, (ctx, img, size) => {
    const crop = 0.8;
    const sx = img.naturalWidth * (1 - crop) / 2;
    const sy = img.naturalHeight * (1 - crop) / 2;
    const sw = img.naturalWidth * crop;
    const sh = img.naturalHeight * crop;
    ctx.drawImage(img, sx, sy, sw, sh, 0, 0, size, size);
  }));

  // 8. Slight horizontal shift (10% right)
  variants.push(drawVariant(img, (ctx, img, size) => {
    const shift = size * 0.1;
    ctx.drawImage(img, 0, 0, img.naturalWidth, img.naturalHeight, shift, 0, size, size);
  }));

  // 9. Partial occlusion (15% random block)
  variants.push(drawVariant(img, (ctx, img, size) => {
    ctx.drawImage(img, 0, 0, size, size);
    const blockSize = size * 0.15;
    const bx = Math.random() * (size - blockSize);
    const by = Math.random() * (size - blockSize);
    ctx.fillStyle = 'rgba(128,128,128,1)';
    ctx.fillRect(bx, by, blockSize, blockSize);
  }));

  return variants;
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Generate CLIP embeddings for all images of an artwork, with augmentation.
 * @param {string[]} imageUrls - Array of image URLs
 * @param {(progress: string) => void} onProgress - Progress callback
 * @returns {Promise<number[][]>} Array of normalized 512-dim embedding vectors
 */
export async function generateEmbeddings(imageUrls, onProgress) {
  const { model, processor } = await initCLIP();

  const allEmbeddings = [];
  let totalVariants = 0;
  let processed = 0;

  totalVariants = imageUrls.length * 9;
  onProgress?.(`CLIP model ready — processing images...`);

  for (let i = 0; i < imageUrls.length; i++) {
    const url = imageUrls[i];
    console.log(`[CLIP] Loading image ${i + 1}/${imageUrls.length}: ${url.substring(0, 80)}...`);
    onProgress?.(`Processing image ${i + 1}/${imageUrls.length}...`);

    let img;
    try {
      img = await loadImage(url);
    } catch (err) {
      console.warn(`[CLIP] Skipping image ${i + 1}: ${err.message}`);
      continue;
    }

    const variants = generateAugmentations(img);

    for (const dataURL of variants) {
      processed++;
      onProgress?.(`Embedding variant ${processed}/${totalVariants}...`);
      try {
        const rawImage = await RawImage.fromURL(dataURL);
        const imageInputs = await processor(rawImage);
        const { image_embeds } = await model(imageInputs);
        const embedding = normalize(Array.from(image_embeds.data));
        // Firestore doesn't support nested arrays — wrap each vector in an object
        allEmbeddings.push({ v: embedding });
      } catch (err) {
        console.warn(`[CLIP] Embedding failed for variant ${processed}:`, err.message);
      }
    }
  }

  onProgress?.(`Done — ${allEmbeddings.length} embeddings generated`);
  return allEmbeddings;
}
